const email = $json;
const text = `${email.subject} ${email.body}`.toLowerCase();

let sentimentLabel = "neutral";
let sentimentScore = 0.0;
let angerScore = 0.1;
let satisfactionScore = 0.4;
let urgencyScore = 0.3;
let summary = "The email has a neutral tone and does not show a strong emotional signal.";

if (
  text.includes("unhappy") ||
  text.includes("angry") ||
  text.includes("refund") ||
  text.includes("delayed") ||
  text.includes("complaint") ||
  text.includes("cancel")
) {
  sentimentLabel = "negative";
  sentimentScore = -0.82;
  angerScore = 0.75;
  satisfactionScore = 0.10;
  urgencyScore = 0.85;
  summary = "The customer expresses dissatisfaction and requests urgent action.";
}

if (
  text.includes("thank") ||
  text.includes("helpful") ||
  text.includes("friendly") ||
  text.includes("solved")
) {
  sentimentLabel = "positive";
  sentimentScore = 0.88;
  angerScore = 0.0;
  satisfactionScore = 0.92;
  urgencyScore = 0.2;
  summary = "The customer expresses satisfaction and positive feedback.";
}

return [
  {
    json: {
      email_id: email.email_id,
      sentiment_label: sentimentLabel,
      sentiment_score: sentimentScore,
      anger_score: angerScore,
      satisfaction_score: satisfactionScore,
      urgency_score: urgencyScore,
      summary: summary
    }
  }
];
